import { Transform, Type } from 'class-transformer';
import { IsString, IsNumber, IsArray, IsUUID, IsDate, IsBoolean } from 'class-validator';

export class BaseTrendingProductsDto {
	@IsUUID()
	_id: string;

	@IsNumber()
	@Type(() => Number)
	style_id: number;

	@IsBoolean()
	@Transform(({ value }: { value: boolean | number | string }) => {
		if (typeof value === 'boolean') return value;
		if (typeof value === 'number') return value === 1;
		if (typeof value === 'string') return value === '1' || value.toLowerCase() === 'true';
		return false;
	})
	is_latest: boolean;

	@IsBoolean()
	@Transform(({ value }: { value: boolean | number | string }) => {
		if (typeof value === 'boolean') return value;
		if (typeof value === 'number') return value === 1;
		if (typeof value === 'string') return value === '1' || value.toLowerCase() === 'true';
		return false;
	})
	is_active: boolean;

	@IsArray()
	@Transform(({ value }: { value: number[] | string }) => {
		if (Array.isArray(value)) return value;
		if (typeof value === 'string') {
			try {
				return JSON.parse(value) as number[];
			} catch {
				return [];
			}
		}
		return [];
	})
	predicted_orders: number[];

	@IsNumber()
	@Type(() => Number)
	total_predicted_orders: number;

	@IsNumber()
	@Type(() => Number)
	trend_score: number;

	@IsString()
	trending_reason: string;

	@IsString()
	@Transform(({ value }: { value: string | Date }) => {
		if (typeof value === 'string') return value;
		if (value instanceof Date) return value.toISOString().split('T')[0];
		return String(value);
	})
	forecast_start_date: string;

	@IsString()
	@Transform(({ value }: { value: string | Date }) => {
		if (typeof value === 'string') return value;
		if (value instanceof Date) return value.toISOString().split('T')[0];
		return String(value);
	})
	forecast_end_date: string;

	@IsNumber()
	@Type(() => Number)
	forecast_days: number;

	@IsDate()
	@Type(() => Date)
	created_at: Date;

	@IsDate()
	@Type(() => Date)
	updated_at: Date;
}

export class CreateTrendingProductsDto {
	@IsString()
	style_id: string;

	@IsArray()
	predicted_orders: number[];

	@IsNumber()
	total_predicted_orders: number;

	@IsNumber()
	trend_score: number;

	@IsString()
	trending_reason: string;

	@IsString()
	@Transform(({ value }: { value: string | Date }) => {
		if (typeof value === 'string') return value;
		if (value instanceof Date) return value.toISOString().split('T')[0];
		return String(value);
	})
	forecast_start_date: string;

	@IsString()
	@Transform(({ value }: { value: string | Date }) => {
		if (typeof value === 'string') return value;
		if (value instanceof Date) return value.toISOString().split('T')[0];
		return String(value);
	})
	forecast_end_date: string;

	@IsNumber()
	forecast_days: number;
}

