const recommendationsHits = results.results[0]?.hits ?? [];
const recommendations = recommendationsHits.map((hit) => {
	return this.mapHitToAlgoliaRelatedProduct(hit as AlgoliaRelatedProductHit);
});

const recoStylesFromDB = await this.styleService.getStylesInStockByIds({
	styleIds: recommendations.reduce<number[]>((acc, rec) => {
		if (Number.isInteger(rec.product_id)) {
			acc.push(rec.product_id);
		}
		return acc;
	}, []),
});

const filteredRecommendations = recommendations.filter((rec) =>
	recoStylesFromDB.some(
		(style) => Number(style.style_id) === Number(rec.product_id),
	),
);

await this.metricsService.incrementDailyCounter(dailyTrackingKeys.ALGOLIA_REQUESTS);
this.logger.log(
	`Storing ${filteredRecommendations.length} related products in cache for productId ${productId}. Cache key: ${cacheKey}. TTL: ${this.relatedProductsCacheTtl} seconds.`,
);
await this.cacheService.set({
	namespace: Namespaces.RELATED_ITEMS_MODEL,
	key: cacheKey,
	value: filteredRecommendations,
	ttl: this.relatedProductsCacheTtl,
});

const colorMatchingStartTime2 = process.hrtime();

const result = filteredRecommendations.map((hit) => {
	return this.mapHitToRelatedProduct(hit as AlgoliaRelatedProductHit, currentStyle);
});

const colorMatchingEndTime = process.hrtime(colorMatchingStartTime2);
const colorMatchingExecutionTime =
	colorMatchingEndTime[0] * 1000 + colorMatchingEndTime[1] / 1e6;

if (colorMatchingExecutionTime > this.executionTimeThreshold) {
	this.logger.warn(
		`[mapHitToRelatedProduct]: Color matching took ${colorMatchingExecutionTime.toFixed(
			2,
		)} ms, which exceeds the threshold of ${this.executionTimeThreshold} ms.`,
	);

